// Parse SSE (Server-Sent Events) stream and accumulate markdown chunks
const body = $input.item.json.body || '';
const lines = body.split('\n');
const chunks = [];

for (const line of lines) {
  if (line.startsWith('data: ')) {
    // Extract the data payload from SSE event
    const data = line.slice(6); // Remove 'data: ' prefix
    // Unescape SSE-encoded newlines
    const unescaped = data.replace(/\\n/g, '\n');
    chunks.push(unescaped);
  }
}

// The last chunk contains the full accumulated markdown
const markdown = chunks.length > 0 ? chunks[chunks.length - 1] : '';

return {
  json: {
    markdown,
    chunk_count: chunks.length,
    received_streaming: true
  }
};
